import os
from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes
from cryptography.hazmat.backends import default_backend

# Load encryption key from config (e.g., environment variable)
ENCRYPTION_KEY = os.environ.get('ENCRYPTION_KEY')

if not ENCRYPTION_KEY:
    raise ValueError("Encryption key is missing. Please set the ENCRYPTION_KEY environment variable.")

def encrypt_credit_card_number(credit_card_number):
    # Generate a random initialization vector
    iv = os.urandom(16)
    
    # Create an AES cipher object with CBC mode
    cipher = Cipher(algorithms.AES(ENCRYPTION_KEY.encode()), modes.CBC(iv), backend=default_backend())
    
    # Encrypt the credit card number
    encryptor = cipher.encryptor()
    padded_number = credit_card_number.ljust(16, '0')  # Pad to multiple of block size
    encrypted_data = encryptor.update(padded_number.encode()) + encryptor.finalize()
    
    # Return IV and encrypted data as bytes
    return iv + encrypted_data

def decrypt_credit_card_number(encrypted_data):
    # Extract the initialization vector from the encrypted data
    iv = encrypted_data[:16]
    encrypted_number = encrypted_data[16:]
    
    # Create an AES cipher object with CBC mode
    cipher = Cipher(algorithms.AES(ENCRYPTION_KEY.encode()), modes.CBC(iv), backend=default_backend())
    
    # Decrypt the credit card number
    decryptor = cipher.decryptor()
    decrypted_padded_number = decryptor.update(encrypted_number) + decryptor.finalize()
    
    # Remove padding and return the original credit card number
    return decrypted_padded_number.decode().rstrip('0')

